#include <bits/stdc++.h>
using namespace std;

const int N=1e3+10;

int n,m,a[N][N],f[N],l[N],r[N],stk[N],top;
long long ans;

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        char s[N];
        scanf("%s",s+1);
        for(int j=1;j<=m;j++)
            a[i][j]=(s[j]=='.');
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++)
            f[j]=a[i][j]*(f[j]+1);
        for(int j=1;j<=m;j++){
            while(top && f[stk[top]]>=f[j])
                r[stk[top]]=j,top--;
            stk[++top]=j;
        }
        while(top)
            r[stk[top]]=m+1,top--;
        for(int j=m;j;j--){
            while(top && f[stk[top]]>f[j])
                l[stk[top]]=j,top--;
            stk[++top]=j;
        }
        while(top)
            l[stk[top]]=0,top--;
        for(int j=1;j<=m;j++)
            ans+=1LL*(r[j]-j)*(j-l[j])*f[j];
    }
    printf("%lld",ans);
    return 0;
}
